/* ============================================
   BREVETTIAMO — Design System
   Mobile-first, A4-friendly, WCAG 2.1 AA
   ============================================ */

/* CSS Variables */
:root {
    --primary: #003366;
    --primary-light: #004080;
    --primary-dark: #002244;
    --accent: #00C853;
    --accent-light: #00E676;
    --warning: #FF9800;
    --danger: #F44336;
    --text: #1a1a2e;
    --text-secondary: #5a5a7a;
    --text-muted: #8a8a9a;
    --bg: #ffffff;
    --bg-secondary: #f8f9fa;
    --bg-tertiary: #eef1f5;
    --border: #e0e0e0;
    --border-light: #f0f0f0;
    --shadow-sm: 0 1px 2px rgba(0,0,0,0.05);
    --shadow: 0 4px 12px rgba(0,0,0,0.08);
    --shadow-lg: 0 8px 24px rgba(0,0,0,0.12);
    --radius-sm: 6px;
    --radius: 12px;
    --radius-lg: 16px;
    --transition: all 0.2s ease;
    --font: 'Inter', -apple-system, BlinkMacSystemFont, sans-serif;
    --max-width: 1200px;
}

/* Reset & Base */
*, *::before, *::after {
    box-sizing: border-box;
    margin: 0;
    padding: 0;
}

html {
    font-size: 16px;
    -webkit-font-smoothing: antialiased;
    -moz-osx-font-smoothing: grayscale;
}

body {
    font-family: var(--font);
    color: var(--text);
    background: var(--bg);
    line-height: 1.6;
    overflow-x: hidden;
}

/* Typography */
h1, h2, h3, h4, h5, h6 {
    font-weight: 700;
    line-height: 1.2;
    color: var(--primary);
}

h1 { font-size: clamp(2rem, 5vw, 3.5rem); }
h2 { font-size: clamp(1.5rem, 3vw, 2.5rem); }
h3 { font-size: clamp(1.2rem, 2vw, 1.5rem); }

p { margin-bottom: 1rem; }

a {
    color: var(--primary);
    text-decoration: none;
    transition: var(--transition);
}

a:hover { color: var(--primary-light); }

/* Container */
.container {
    max-width: var(--max-width);
    margin: 0 auto;
    padding: 0 1.5rem;
}

/* Buttons */
.btn {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    gap: 0.5rem;
    padding: 0.75rem 1.5rem;
    border-radius: var(--radius);
    font-weight: 600;
    font-size: 0.95rem;
    cursor: pointer;
    border: 2px solid transparent;
    transition: var(--transition);
    text-decoration: none;
    white-space: nowrap;
}

.btn-primary {
    background: var(--primary);
    color: white;
    border-color: var(--primary);
}

.btn-primary:hover {
    background: var(--primary-light);
    border-color: var(--primary-light);
    transform: translateY(-1px);
    box-shadow: var(--shadow);
}

.btn-outline {
    background: transparent;
    color: var(--primary);
    border-color: var(--primary);
}

.btn-outline:hover {
    background: var(--primary);
    color: white;
}

.btn-ghost {
    background: transparent;
    color: var(--text-secondary);
    border-color: transparent;
}

.btn-ghost:hover {
    background: var(--bg-secondary);
    color: var(--text);
}

.btn-large {
    padding: 1rem 2rem;
    font-size: 1.1rem;
    border-radius: var(--radius-lg);
}

.btn-note {
    display: block;
    font-size: 0.75rem;
    font-weight: 400;
    opacity: 0.8;
    margin-top: 0.25rem;
}

/* Navbar */
.navbar {
    position: fixed;
    top: 0;
    left: 0;
    right: 0;
    background: rgba(255,255,255,0.95);
    backdrop-filter: blur(10px);
    border-bottom: 1px solid var(--border-light);
    z-index: 1000;
    padding: 0.75rem 0;
}

.navbar .container {
    display: flex;
    align-items: center;
    justify-content: space-between;
}

.logo {
    display: flex;
    align-items: center;
    gap: 0.75rem;
    font-weight: 800;
    font-size: 1.25rem;
    color: var(--primary);
}

.logo .accent {
    color: var(--accent);
}

.nav-links {
    display: flex;
    align-items: center;
    gap: 0.75rem;
}

.mobile-menu-toggle {
    display: none;
    flex-direction: column;
    gap: 4px;
    background: none;
    border: none;
    cursor: pointer;
    padding: 0.5rem;
}

.mobile-menu-toggle span {
    width: 24px;
    height: 2px;
    background: var(--primary);
    transition: var(--transition);
}

/* Hero */
.hero {
    padding: 8rem 0 4rem;
    background: linear-gradient(135deg, var(--bg) 0%, var(--bg-secondary) 100%);
    min-height: 100vh;
    display: flex;
    align-items: center;
}

.hero .container {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 4rem;
    align-items: center;
}

.hero-content h1 {
    margin-bottom: 1.5rem;
}

.hero-content .highlight {
    color: var(--accent);
    position: relative;
}

.hero-content .highlight::after {
    content: '';
    position: absolute;
    bottom: 0;
    left: 0;
    right: 0;
    height: 8px;
    background: rgba(0,200,83,0.2);
    border-radius: 4px;
}

.hero-subtitle {
    font-size: 1.15rem;
    color: var(--text-secondary);
    margin-bottom: 1.5rem;
    max-width: 500px;
}

.hero-price {
    font-size: 1.25rem;
    margin-bottom: 2rem;
}

.hero-price strong {
    font-size: 2rem;
    color: var(--primary);
}

.hero-price .price-note {
    display: block;
    font-size: 0.85rem;
    color: var(--text-muted);
    margin-top: 0.5rem;
}

.hero-cta {
    display: flex;
    flex-direction: column;
    gap: 1rem;
    margin-bottom: 2rem;
    max-width: 400px;
}

.hero-cta .btn {
    justify-content: flex-start;
    text-align: left;
}

.hero-trust {
    display: flex;
    flex-wrap: wrap;
    gap: 1rem;
    font-size: 0.85rem;
    color: var(--text-muted);
}

/* Document Preview */
.document-preview {
    background: white;
    border-radius: var(--radius-lg);
    box-shadow: var(--shadow-lg);
    overflow: hidden;
    border: 1px solid var(--border);
}

.doc-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 1rem 1.5rem;
    background: var(--bg-secondary);
    border-bottom: 1px solid var(--border);
}

.doc-badge {
    background: var(--accent);
    color: white;
    padding: 0.25rem 0.75rem;
    border-radius: 20px;
    font-size: 0.75rem;
    font-weight: 600;
}

.doc-status {
    color: var(--accent);
    font-weight: 600;
    font-size: 0.85rem;
}

.doc-content {
    padding: 1.5rem;
}

.doc-line {
    height: 12px;
    background: var(--bg-tertiary);
    border-radius: 4px;
    margin-bottom: 0.75rem;
    width: 100%;
}

.doc-line.short { width: 60%; }
.doc-line.title { width: 80%; height: 16px; }

.doc-figure {
    margin-top: 1rem;
    padding: 1rem;
    background: var(--bg-secondary);
    border-radius: var(--radius);
    text-align: center;
}

.doc-figure svg {
    max-width: 100%;
    height: auto;
}

.doc-figure span {
    display: block;
    margin-top: 0.5rem;
    font-size: 0.8rem;
    color: var(--text-muted);
}

/* Pricing */
.pricing {
    padding: 5rem 0;
    background: var(--bg-secondary);
}

.pricing h2 {
    text-align: center;
    margin-bottom: 0.5rem;
}

.section-subtitle {
    text-align: center;
    color: var(--text-secondary);
    margin-bottom: 3rem;
}

.pricing-grid {
    display: grid;
    grid-template-columns: repeat(3, 1fr);
    gap: 2rem;
    max-width: 1000px;
    margin: 0 auto;
}

.pricing-card {
    background: white;
    border-radius: var(--radius-lg);
    padding: 2rem;
    box-shadow: var(--shadow);
    border: 2px solid var(--border);
    position: relative;
    transition: var(--transition);
}

.pricing-card:hover {
    transform: translateY(-4px);
    box-shadow: var(--shadow-lg);
}

.pricing-card.popular {
    border-color: var(--primary);
    transform: scale(1.05);
}

.pricing-card.popular:hover {
    transform: scale(1.05) translateY(-4px);
}

.card-badge {
    position: absolute;
    top: -12px;
    left: 50%;
    transform: translateX(-50%);
    background: var(--primary);
    color: white;
    padding: 0.35rem 1rem;
    border-radius: 20px;
    font-size: 0.75rem;
    font-weight: 700;
    text-transform: uppercase;
    letter-spacing: 0.5px;
}

.pricing-card.free .card-badge {
    background: var(--accent);
}

.pricing-card h3 {
    text-align: center;
    margin-bottom: 0.5rem;
}

.price {
    font-size: 2.5rem;
    font-weight: 800;
    text-align: center;
    color: var(--primary);
    margin-bottom: 0.25rem;
}

.price-note {
    text-align: center;
    font-size: 0.8rem;
    color: var(--text-muted);
    margin-bottom: 1.5rem;
}

.pricing-card ul {
    list-style: none;
    margin-bottom: 2rem;
}

.pricing-card li {
    padding: 0.5rem 0;
    font-size: 0.9rem;
    border-bottom: 1px solid var(--border-light);
}

.pricing-card li:last-child {
    border-bottom: none;
}

.pricing-card .btn {
    width: 100%;
}

/* How It Works */
.how-it-works {
    padding: 5rem 0;
}

.how-it-works h2 {
    text-align: center;
    margin-bottom: 3rem;
}

.steps {
    display: grid;
    grid-template-columns: repeat(5, 1fr);
    gap: 1.5rem;
}

.step {
    text-align: center;
    padding: 1.5rem;
    position: relative;
}

.step-number {
    width: 32px;
    height: 32px;
    background: var(--primary);
    color: white;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    font-weight: 700;
    font-size: 0.85rem;
    margin: 0 auto 1rem;
}

.step-icon {
    font-size: 2rem;
    margin-bottom: 0.75rem;
}

.step h3 {
    font-size: 1rem;
    margin-bottom: 0.5rem;
}

.step p {
    font-size: 0.85rem;
    color: var(--text-secondary);
}

/* Studio Section */
.studio-section {
    padding: 5rem 0;
    background: linear-gradient(135deg, var(--primary) 0%, var(--primary-dark) 100%);
    color: white;
}

.studio-section h2,
.studio-section h3 {
    color: white;
}

.studio-content {
    max-width: 800px;
    margin: 0 auto;
    text-align: center;
}

.studio-lead {
    font-size: 1.25rem;
    opacity: 0.9;
    margin-bottom: 2rem;
}

.studio-plans {
    display: grid;
    grid-template-columns: repeat(2, 1fr);
    gap: 2rem;
    margin-bottom: 2rem;
}

.studio-plan {
    background: rgba(255,255,255,0.1);
    border-radius: var(--radius);
    padding: 2rem;
    border: 1px solid rgba(255,255,255,0.2);
}

.studio-plan.featured {
    background: rgba(255,255,255,0.15);
    border-color: var(--accent);
}

.studio-plan .price {
    color: white;
    font-size: 2rem;
}

.studio-plan .price span {
    font-size: 1rem;
    opacity: 0.7;
}

.studio-plan ul {
    list-style: none;
    text-align: left;
    margin-top: 1rem;
}

.studio-plan li {
    padding: 0.5rem 0;
    font-size: 0.9rem;
    opacity: 0.9;
}

.studio-section .btn-outline {
    border-color: white;
    color: white;
}

.studio-section .btn-outline:hover {
    background: white;
    color: var(--primary);
}

/* Trust */
.trust {
    padding: 5rem 0;
    background: var(--bg-secondary);
}

.trust h2 {
    text-align: center;
    margin-bottom: 3rem;
}

.trust-grid {
    display: grid;
    grid-template-columns: repeat(3, 1fr);
    gap: 2rem;
}

.trust-item {
    text-align: center;
    padding: 2rem;
    background: white;
    border-radius: var(--radius);
    box-shadow: var(--shadow-sm);
    transition: var(--transition);
}

.trust-item:hover {
    transform: translateY(-2px);
    box-shadow: var(--shadow);
}

.trust-icon {
    font-size: 2.5rem;
    margin-bottom: 1rem;
}

.trust-item h3 {
    font-size: 1.1rem;
    margin-bottom: 0.5rem;
}

.trust-item p {
    font-size: 0.9rem;
    color: var(--text-secondary);
    margin-bottom: 0;
}

/* CTA Final */
.cta-final {
    padding: 5rem 0;
    text-align: center;
    background: var(--bg);
}

.cta-final h2 {
    margin-bottom: 1rem;
}

.cta-final p {
    font-size: 1.15rem;
    color: var(--text-secondary);
    margin-bottom: 2rem;
}

.cta-note {
    font-size: 0.85rem;
    color: var(--text-muted);
    margin-top: 1rem;
}

/* Footer */
footer {
    background: var(--primary-dark);
    color: white;
    padding: 3rem 0 1.5rem;
}

.footer-grid {
    display: grid;
    grid-template-columns: 2fr 1fr 1fr 1fr;
    gap: 3rem;
    margin-bottom: 2rem;
}

.footer-brand .logo {
    color: white;
    margin-bottom: 1rem;
}

.footer-brand p {
    opacity: 0.7;
    font-size: 0.9rem;
}

.footer-links h4 {
    color: white;
    font-size: 0.9rem;
    margin-bottom: 1rem;
    text-transform: uppercase;
    letter-spacing: 0.5px;
}

.footer-links a {
    display: block;
    color: rgba(255,255,255,0.7);
    padding: 0.35rem 0;
    font-size: 0.9rem;
}

.footer-links a:hover {
    color: white;
}

.footer-bottom {
    border-top: 1px solid rgba(255,255,255,0.1);
    padding-top: 1.5rem;
    display: flex;
    justify-content: space-between;
    font-size: 0.85rem;
    opacity: 0.6;
}

/* ============================================
   RESPONSIVE
   ============================================ */

@media (max-width: 1024px) {
    .hero .container {
        grid-template-columns: 1fr;
        gap: 2rem;
    }

    .hero-visual {
        order: -1;
        max-width: 500px;
        margin: 0 auto;
    }

    .steps {
        grid-template-columns: repeat(3, 1fr);
    }

    .trust-grid {
        grid-template-columns: repeat(2, 1fr);
    }
}

@media (max-width: 768px) {
    .nav-links {
        display: none;
    }

    .mobile-menu-toggle {
        display: flex;
    }

    .hero {
        padding: 6rem 0 3rem;
        min-height: auto;
    }

    .hero-cta {
        max-width: 100%;
    }

    .pricing-grid {
        grid-template-columns: 1fr;
        max-width: 400px;
    }

    .pricing-card.popular {
        transform: none;
    }

    .pricing-card.popular:hover {
        transform: translateY(-4px);
    }

    .steps {
        grid-template-columns: repeat(2, 1fr);
    }

    .studio-plans {
        grid-template-columns: 1fr;
    }

    .trust-grid {
        grid-template-columns: 1fr;
    }

    .footer-grid {
        grid-template-columns: 1fr 1fr;
        gap: 2rem;
    }

    .footer-bottom {
        flex-direction: column;
        gap: 0.5rem;
        text-align: center;
    }
}

@media (max-width: 480px) {
    .steps {
        grid-template-columns: 1fr;
    }

    .footer-grid {
        grid-template-columns: 1fr;
    }

    .hero-trust {
        flex-direction: column;
        gap: 0.5rem;
    }
}

/* ============================================
   UTILITIES
   ============================================ */

.sr-only {
    position: absolute;
    width: 1px;
    height: 1px;
    padding: 0;
    margin: -1px;
    overflow: hidden;
    clip: rect(0, 0, 0, 0);
    white-space: nowrap;
    border: 0;
}

.text-center { text-align: center; }
.text-primary { color: var(--primary); }
.text-accent { color: var(--accent); }
.text-muted { color: var(--text-muted); }

.mt-1 { margin-top: 0.5rem; }
.mt-2 { margin-top: 1rem; }
.mt-3 { margin-top: 1.5rem; }
.mt-4 { margin-top: 2rem; }

.mb-1 { margin-bottom: 0.5rem; }
.mb-2 { margin-bottom: 1rem; }
.mb-3 { margin-bottom: 1.5rem; }
.mb-4 { margin-bottom: 2rem; }

