            ]
        },
        {
            id: 'disegnipiù',
            nome: 'Disegni+ / Marchi+',
            importo: '€10.000-50.000',
            copertura: 40,
            target: ['micro', 'piccola', 'media'],
            tipi: ['disegno', 'marchio'],
            regioni: ['tutte'],
            stato: 'in-arrivo',
            ente: 'ICE / MISE',
            requisiti: [
